mapper.select:
    select 

    from ${tableName}

    where uidentify = #{companyCode,jdbcType=VARCHAR}
		and DATE(TIME) >= DATE(#{startTime,jdbcType=TIMESTAMP}) 
		and DATE(TIME) <= DATE(#{endTime,jdbcType=TIMESTAMP}) 
		order by time asc

select 
uidentify, INDEX_CODE, TIME,VALUE
from ${tableName} limit ${start},${limit}


select 
uidentify, INDEX_CODE, TIME,VALUE
from ${tableName}
where  DATE_ADD(DATE(TIME),INTERVAL 2 DAY) >= DATE(#{stime,jdbcType=TIMESTAMP}) 
and DATE_ADD(DATE(TIME),INTERVAL -2 DAY) <= DATE(#{etime,jdbcType=TIMESTAMP}) 
limit ${start},${limit}

select 
uidentify, INDEX_CODE, TIME,VALUE
from ${tableName} where uidentify = #{companyCode,jdbcType=VARCHAR}

select 
uidentify, INDEX_CODE, TIME,VALUE
from ${tableName} where INDEX_CODE = #{indexcode,jdbcType=VARCHAR}

select 
uidentify, INDEX_CODE, TIME,VALUE
from ${tableName} where INDEX_CODE in ${indexcodes}
